// ============================================
// Kampagne + Leads aus Supabase laden
// ============================================
const webhookData = $input.first().json;
const payload = webhookData.body ?? webhookData;
const campaignId = payload.campaign_id;
const userId = payload.user_id;

if (!campaignId) throw new Error('campaign_id fehlt im Webhook-Payload');

const supabaseUrl = 'https://kvwjabdmmdthgbhimjqf.supabase.co';
const supabaseKey = 'YOUR_SUPABASE_SERVICE_ROLE_KEY_HERE';
const headers = {
  'apikey': supabaseKey,
  'Authorization': 'Bearer ' + supabaseKey,
  'Content-Type': 'application/json'
};

const campaigns = await this.helpers.httpRequest({
  method: 'GET',
  url: supabaseUrl + '/rest/v1/campaigns?id=eq.' + campaignId + '&select=id,daily_limit,delay_minutes,reply_to,status',
  headers
});
const campaign = campaigns[0];

if (!campaign) throw new Error('Kampagne ' + campaignId + ' nicht gefunden');
if (campaign.status !== 'active') throw new Error('Kampagne nicht aktiv (' + campaign.status + ')');

const leads = await this.helpers.httpRequest({
  method: 'GET',
  url: supabaseUrl + '/rest/v1/campaign_leads?campaign_id=eq.' + campaignId + '&status=eq.pending&select=id,tracking_token,campaign_id,lead_id,lead:leads(company,company_name,email,phone,website,city,postal_code,street,country,industry,legal_form,ceo_name,ceo_title,ceo_first_name,ceo_last_name,ceo_gender)',
  headers
});

if (!leads || leads.length === 0) {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: supabaseUrl + '/rest/v1/campaigns?id=eq.' + campaignId,
    headers: { ...headers, 'Prefer': 'return=minimal' },
    body: { status: 'completed', completed_at: new Date().toISOString() }
  });
  return [{ json: { message: 'Keine offenen Leads - Kampagne abgeschlossen', done: true } }];
}

return leads.map(lead => ({
  json: {
    ...lead,
    daily_limit: campaign.daily_limit,
    delay_minutes: campaign.delay_minutes,
    reply_to: campaign.reply_to
  }
}));

const allLeads = $input.all();
if (!allLeads.length || allLeads[0].json.done) return [];
const DAILY_LIMIT = allLeads[0].json.daily_limit || 200;
return allLeads.slice(0, DAILY_LIMIT).map(item => ({ json: item.json }));

const senderDomains = [
  { id: 1,  email: 'beratung@ki-kanzlei.at',    name: 'KI Kanzlei AI' },
  { id: 2,  email: 'team@ki-kanzlei.at',         name: 'KI Kanzlei Team' },
  { id: 3,  email: 'dialog@ki-kanzlei.at',       name: 'KI Kanzlei Austausch' },
  { id: 4,  email: 'hello@ki-kanzlei.at',        name: 'KI Kanzlei Automatisierung' },
  { id: 5,  email: 'office@ki-kanzlei.at',       name: 'KI Kanzlei Beratung' },
  { id: 6,  email: 'connect@ki-kanzlei.at',      name: 'KI Kanzlei Contact' },
  { id: 7,  email: 'digital@ki-kanzlei.at',      name: 'KI Kanzlei Digitalisierung' },
  { id: 8,  email: 'kontakt@ki-kanzlei.at',      name: 'KI Kanzlei Effizienz' },
  { id: 9,  email: 'welcome@ki-kanzlei.at',      name: 'KI Kanzlei Hello' },
  { id: 10, email: 'solutions@ki-kanzlei.at',    name: 'KI Kanzlei KI-Loesungen' },
  { id: 11, email: 'anfrage@ki-kanzlei.at',      name: 'KI Kanzlei Kontakt' },
  { id: 12, email: 'support@ki-kanzlei.at',      name: 'KI Kanzlei Loesungen' },
  { id: 13, email: 'optimierung@ki-kanzlei.at',  name: 'KI Kanzlei Prozesse' },
  { id: 14, email: 'wachstum@ki-kanzlei.at',     name: 'KI Kanzlei Strategie' },
  { id: 15, email: 'projekt@ki-kanzlei.at',      name: 'KI Kanzlei Umsetzung' }
];

const lead = $input.item.json;
const domainIndex = $itemIndex % senderDomains.length;
const selectedDomain = senderDomains[domainIndex];

return {
  ...lead,
  senderEmail: selectedDomain.email,
  senderName: selectedDomain.name,
  replyTo: lead.reply_to || 'info@ki-kanzlei.at',
  domainId: selectedDomain.id
};

// ============================================
// Status-Check: Ist die Kampagne noch aktiv?
// Wird VOR jeder Mail geprüft — ermöglicht Pause/Stop vom Dashboard
// ============================================
const self = this;
const loopData = $input.item.json;
const campaignId = loopData.campaign_id;

const supabaseUrl = 'https://kvwjabdmmdthgbhimjqf.supabase.co';
const supabaseKey = 'YOUR_SUPABASE_SERVICE_ROLE_KEY_HERE';

const campaigns = await self.helpers.httpRequest({
  method: 'GET',
  url: supabaseUrl + '/rest/v1/campaigns?id=eq.' + campaignId + '&select=status',
  headers: {
    'apikey': supabaseKey,
    'Authorization': 'Bearer ' + supabaseKey,
    'Content-Type': 'application/json'
  }
});

const status = campaigns[0]?.status;

if (status !== 'active') {
  console.log('⏸️ Kampagne nicht mehr aktiv (status=' + status + ') — Loop wird gestoppt');
  return { stopped: true, reason: 'Kampagne ' + status };
}

return loopData;

const item = $input.item.json;
const html = item.data || '';

const metaDescMatch = html.match(/<meta name="description" content="([^"]*)"/i);
const metaDescription = metaDescMatch ? metaDescMatch[1] : '';

const titleMatch = html.match(/<title>([^<]*)<\/title>/i);
const pageTitle = titleMatch ? titleMatch[1].replace(/&#\d+;/g, '').replace(/&raquo;/g, '»').trim() : '';

let text = html
  .replace(/<script[^>]*>.*?<\/script>/gis, '')
  .replace(/<style[^>]*>.*?<\/style>/gis, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

text = text
  .replace(/&#(\d+);/g, (match, dec) => String.fromCharCode(dec))
  .replace(/&nbsp;/g, ' ')
  .replace(/&quot;/g, '"')
  .replace(/&amp;/g, '&')
  .replace(/&raquo;/g, '»')
  .substring(0, 3000);

return { pageTitle, metaDescription, websiteText: text };

