const executionData = $json.execution;
const errorData = executionData.error;
const workflowData = $json.workflow;
const timestamp = new Date(Date.now() + 60*60*1000).toLocaleString('de-AT', {
  day: '2-digit', month: '2-digit', year: '2-digit',
  hour: '2-digit', minute: '2-digit', second: '2-digit'
});

// Kampagne auf paused setzen + Fehler speichern
try {
  const supabaseUrl = 'https://kvwjabdmmdthgbhimjqf.supabase.co';
  const supabaseKey = 'YOUR_SUPABASE_SERVICE_ROLE_KEY_HERE';
  const supaHeaders = {
    'apikey': supabaseKey,
    'Authorization': 'Bearer ' + supabaseKey,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  };

  // Aktive Kampagnen finden die zu diesem Workflow gehoeren
  const campaigns = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/campaigns?status=eq.active&select=id',
    headers: { 'apikey': supabaseKey, 'Authorization': 'Bearer ' + supabaseKey, 'Content-Type': 'application/json' }
  });

  const errorMsg = '[n8n Fehler] ' + (executionData.lastNodeExecuted || 'Unbekannt') + ': ' + (errorData.message || 'Unbekannter Fehler');

  for (const c of (campaigns || [])) {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: supabaseUrl + '/rest/v1/campaigns?id=eq.' + c.id,
      headers: supaHeaders,
      body: {
        status: 'paused',
        error_message: errorMsg.substring(0, 500)
      }
    });
  }
} catch (e) {
  console.log('Fehler beim Kampagne-Update: ' + e.message);
}

return [{ json: {
  customer_name: 'KI Kanzlei',
  workflow_name: workflowData.name,
  error_node: executionData.lastNodeExecuted,
  error_message: errorData.message,
  execution_id: executionData.id.toString(),
  execution_url: executionData.url,
  instance_url: 'https://n8n.srv1215699.hstgr.cloud/',
  timestamp: timestamp
}}];
